import{_ as t,a as n,b as i}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as a,o as d,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Cloudflare-R2-Kanal hinzufügen","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/upload/cloudflare-r2.md","filePath":"de-DE/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),o={name:"de-DE/upload/cloudflare-r2.md"};function u(s,e,c,h,g,b){return d(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="cloudflare-r2-kanal-hinzufugen" tabindex="-1">Cloudflare-R2-Kanal hinzufügen <a class="header-anchor" href="#cloudflare-r2-kanal-hinzufugen" aria-label="Permalink to &quot;Cloudflare-R2-Kanal hinzufügen&quot;">​</a></h1><h2 id="geeignet-fur" tabindex="-1">Geeignet für <a class="header-anchor" href="#geeignet-fur" aria-label="Permalink to &quot;Geeignet für&quot;">​</a></h2><p>Nutze Cloudflare R2, wenn:</p><ul><li>deine ImgBed-Seite bereits auf Cloudflare läuft und Dateien in einem R2-Bucket desselben Cloudflare-Kontos gespeichert werden sollen.</li><li>du keinen separaten S3-Endpoint mit Access Key und Secret Key einrichten möchtest.</li><li>Lese- und Schreibzugriffe möglichst einfach über das R2-Binding von Worker oder Pages laufen sollen.</li></ul><p>Kurz gesagt:</p><p>Der R2-Kanal wird nicht manuell im ImgBed-Adminbereich angelegt. Du bindest zuerst einen R2-Bucket an das Cloudflare-Projekt. Der Name der Binding-Variable muss exakt <code>img_r2</code> lauten.</p><h2 id="was-du-vorher-brauchst" tabindex="-1">Was du vorher brauchst <a class="header-anchor" href="#was-du-vorher-brauchst" aria-label="Permalink to &quot;Was du vorher brauchst&quot;">​</a></h2><ul><li>Ein Cloudflare-Konto.</li><li>Einen bestehenden R2-Bucket.</li><li>Berechtigung, das Cloudflare-Projekt zu verwalten, auf dem ImgBed bereitgestellt ist.</li></ul><h2 id="in-cloudflare-einrichten" tabindex="-1">In Cloudflare einrichten <a class="header-anchor" href="#in-cloudflare-einrichten" aria-label="Permalink to &quot;In Cloudflare einrichten&quot;">​</a></h2><h3 id="_1-r2-bucket-erstellen" tabindex="-1">1. R2-Bucket erstellen <a class="header-anchor" href="#_1-r2-bucket-erstellen" aria-label="Permalink to &quot;1. R2-Bucket erstellen&quot;">​</a></h3><ol><li>Melde dich im Cloudflare Dashboard an.</li><li>Öffne <code>R2 Object Storage</code>.</li><li>Klicke auf Bucket erstellen.</li><li>Wähle einen Bucket-Namen, zum Beispiel <code>imgbed</code>.</li></ol><p>In diesem Bucket werden später die hochgeladenen Dateien gespeichert.</p><p><img src="'+t+'" alt="R2-Bucket erstellen" loading="lazy"></p><h3 id="_2-bucket-an-das-imgbed-projekt-binden" tabindex="-1">2. Bucket an das ImgBed-Projekt binden <a class="header-anchor" href="#_2-bucket-an-das-imgbed-projekt-binden" aria-label="Permalink to &quot;2. Bucket an das ImgBed-Projekt binden&quot;">​</a></h3><p>Wähle den Binding-Ort passend zu deiner Bereitstellung:</p><table tabindex="0"><thead><tr><th>Bereitstellung</th><th>Binding-Ort</th></tr></thead><tbody><tr><td>Pages</td><td>Aktuelles Pages-Projekt -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Aktueller Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>Beim Hinzufügen des Bindings sind diese Felder wichtig:</p><table tabindex="0"><thead><tr><th>Feld</th><th>Wert</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>Den gerade erstellten Bucket auswählen</td></tr></tbody></table><p>Der Variablenname muss genau <code>img_r2</code> sein. Hochladen, Lesen und Löschen von R2-Dateien hängen alle an diesem Binding-Namen.</p><h3 id="_3-projekt-erneut-bereitstellen" tabindex="-1">3. Projekt erneut bereitstellen <a class="header-anchor" href="#_3-projekt-erneut-bereitstellen" aria-label="Permalink to &quot;3. Projekt erneut bereitstellen&quot;">​</a></h3><p>Speichere das Binding und deploye ImgBed danach neu, damit die Worker- oder Pages-Laufzeit auf <code>img_r2</code> zugreifen kann.</p><h2 id="was-du-in-imgbed-siehst" tabindex="-1">Was du in ImgBed siehst <a class="header-anchor" href="#was-du-in-imgbed-siehst" aria-label="Permalink to &quot;Was du in ImgBed siehst&quot;">​</a></h2><p>Sobald das R2-Binding verfügbar ist, öffne:</p><ol><li>Systemeinstellungen.</li><li>Upload-Einstellungen.</li><li>Den Kanal <code>Cloudflare R2</code>.</li></ol><p>Das System erstellt automatisch einen festen Kanal:</p><table tabindex="0"><thead><tr><th>Feld</th><th>Fester Wert</th></tr></thead><tbody><tr><td>Kanalname</td><td><code>Cloudflare R2</code></td></tr><tr><td>Kanaltyp</td><td><code>cfr2</code></td></tr><tr><td>Speichermodus</td><td><code>binding</code></td></tr><tr><td>Konfigurationsquelle</td><td>Environment Binding</td></tr></tbody></table><p>Das ist ein fest gebundener Kanal. Du musst nicht auf Kanal hinzufügen klicken, um ihn anzulegen, und er lässt sich nicht wie ein normaler Kanal löschen.</p><h2 id="bearbeitbare-felder-im-adminbereich" tabindex="-1">Bearbeitbare Felder im Adminbereich <a class="header-anchor" href="#bearbeitbare-felder-im-adminbereich" aria-label="Permalink to &quot;Bearbeitbare Felder im Adminbereich&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feld</th><th>Funktion</th><th>Erforderlich</th></tr></thead><tbody><tr><td>Kanal aktivieren</td><td>Legt fest, ob R2 bei der Upload-Auswahl verwendet wird.</td><td>Ja</td></tr><tr><td>Account ID</td><td>Wird nur benötigt, wenn Quotenlimits aktiv sind und die offizielle R2-Nutzung abgefragt werden soll.</td><td>Empfohlen bei aktivierten Quotenlimits</td></tr><tr><td>Bucket-Name</td><td>Wird nur benötigt, wenn Quotenlimits aktiv sind und die offizielle R2-Nutzung abgefragt werden soll.</td><td>Empfohlen bei aktivierten Quotenlimits</td></tr><tr><td>Quotenlimit</td><td>Steuert, ob dieser R2-Kanal abhängig von der Kapazität bei Uploads berücksichtigt wird.</td><td>Nein</td></tr><tr><td>Schwellenwert</td><td>Stoppt Schreibvorgänge auf diesen Kanal, sobald die angegebene Nutzung erreicht ist.</td><td>Erforderlich bei aktivierten Quotenlimits</td></tr></tbody></table><p>Die Account ID findest du im Kontoinformationsbereich des Cloudflare Dashboards. Trage sie nur ein, wenn ImgBed die R2-Nutzung abfragen und anhand der Quote steuern soll.</p><p><img src="'+n+'" alt="Account ID abrufen" loading="lazy"></p><h2 id="einrichtungsschritte" tabindex="-1">Einrichtungsschritte <a class="header-anchor" href="#einrichtungsschritte" aria-label="Permalink to &quot;Einrichtungsschritte&quot;">​</a></h2><ol><li>Erstelle in Cloudflare einen R2-Bucket.</li><li>Öffne die Cloudflare-Einstellungen des ImgBed-Projekts.</li><li>Füge ein R2-Bucket-Binding hinzu.</li><li>Setze <code>Variable name</code> auf <code>img_r2</code>.</li><li>Wähle den erstellten R2-Bucket aus.</li><li>Speichere das Binding und deploye ImgBed neu.</li><li>Kehre zu ImgBed -&gt; Systemeinstellungen -&gt; Upload-Einstellungen zurück.</li><li>Prüfe, ob der Kanal <code>Cloudflare R2</code> erscheint und aktiviert ist.</li></ol><p>Wenn R2 anhand der Kapazität bei der Upload-Auswahl berücksichtigt werden soll, aktiviere das Quotenlimit und trage vor dem Speichern Account ID, Bucket-Name, Quotenlimit und Schwellenwert ein.</p><p><img src="'+i+'" alt="Quotenlimit konfigurieren" loading="lazy"></p><h2 id="prufung" tabindex="-1">Prüfung <a class="header-anchor" href="#prufung" aria-label="Permalink to &quot;Prüfung&quot;">​</a></h2><ul><li>Der feste Kanal <code>Cloudflare R2</code> erscheint in den Upload-Einstellungen.</li><li>Die Kanalkarte zeigt, dass der Kanal aktiv ist.</li><li>Eine kleine Testdatei wird erfolgreich hochgeladen und der zurückgegebene Link öffnet sich normal.</li><li>Wenn beim Öffnen einer Datei <code>R2 database binding is not configured</code> erscheint, hat die Laufzeit das Binding <code>img_r2</code> nicht erhalten. Prüfe den Binding-Namen in Cloudflare und deploye das Projekt erneut.</li></ul>',37)])])}const k=a(o,[["render",u]]);export{p as __pageData,k as default};
